/// A simple UUID v4 generator using Dart's Random class.
/// Generates RFC 4122 compliant version 4 UUIDs.
class UUIDGenerator {
  final Random _random;

  UUIDGenerator({bool secure = true})
      : _random = secure ? Random.secure() : Random();

  /// Generates a single UUID v4 string.
  /// Format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
  /// where x is any hex digit and y is one of 8, 9, a, or b.
  String generate() {
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Set version to 4 (bits 12-15 of time_hi_and_version)
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (bits 6-7 of clock_seq_hi_and_reserved)
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatAsUUID(bytes);
  }

  /// Generates a batch of UUIDs.
  List<String> generateBatch(int count) {
    return List<String>.generate(count, (_) => generate());
  }

  /// Generates a short ID (first 8 characters of a UUID) for compact use.
  String generateShort() {
    return generate().split('-').first;
  }

  /// Generates a timestamp-prefixed UUID for sortable unique IDs.
  /// Format: <unix_timestamp_hex>-<uuid_v4>
  String generateTimestamped() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final hexTimestamp = timestamp.toRadixString(16).padLeft(12, '0');
    return '$hexTimestamp-${generate()}';
  }

  String _formatAsUUID(List<int> bytes) {
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    return '${hex.substring(0, 8)}-'
        '${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-'
        '${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }
}

/// Represents an offline data entry with a unique ID.
class OfflineRecord {
  final String id;
  final String title;
  final String content;
  final DateTime createdAt;
  bool isSynced;

  OfflineRecord({
    required this.id,
    required this.title,
    required this.content,
    required this.createdAt,
    this.isSynced = false,
  });
}

