        content: Text('Deleted record: ${record.title}'),
        behavior: SnackBarBehavior.floating,
        action: SnackBarAction(
          label: 'Undo',
          onPressed: () {
            setState(() {
              _records.insert(index, record);
            });
          },
        ),
      ),
    );
  }

